/**
 * A minimal DOM read/write scheduler to prevent layout thrashing.
 * Loosely based on https://github.com/wilsonpage/fastdom and using the same API.
 */

const noop = () => {};

// Access latency instrumentation hooks from the global object, if available.
// This isn't ideal, but we need it outside of React context and w/o creating additional dependencies.
export type InstrumentedGlobal = typeof globalThis & {
  __perfHooks?: {
    rit?: {
      blockActiveInteractions?: (holdName: string) => () => void;
    };
  };
};

function blockActiveInteractions(holdName: string): () => void {
  return (globalThis as InstrumentedGlobal).__perfHooks?.rit?.blockActiveInteractions?.(holdName) ?? noop;
}

type TaskFn = () => void;

interface Task {
  fn: TaskFn;
  resolve: () => void;
  reject: (error: Error) => void;
}

export interface CancellablePromise extends Promise<void> {
  cancel: () => void;
}

let measureQueue: Task[] = [];
let updateQueue: Task[] = [];
let isScheduled = false;

let releaseInteractionHolds = noop;

function runTasks(tasks: Task[]): void {
  tasks.forEach((task) => {
    try {
      task.fn();
      task.resolve();
    } catch (error) {
      task.reject(error as Error);
    }
  });
}

function flush(): void {
  isScheduled = false;

  // Snapshot and clear queues to prevent tasks queued during flush from running in the same frame.
  const [tasksToMeasure, tasksToUpdate] = [measureQueue, updateQueue];
  measureQueue = [];
  updateQueue = [];

  const releaseAfterFlush = releaseInteractionHolds;

  try {
    let start = performance.now();
    runTasks(tasksToMeasure);
    performance.measure('fastdom-measure', {
      start,
      end: performance.now(),
      detail: {
        tasks: tasksToMeasure.length,
      },
    });

    start = performance.now();
    runTasks(tasksToUpdate);
    performance.measure('fastdom-update', {
      start,
      end: performance.now(),
      detail: {
        tasks: tasksToUpdate.length,
      },
    });
  } finally {
    // Release the interaction holds after the flush has completed.
    releaseAfterFlush();
  }
}

function scheduleFlush(): void {
  if (!isScheduled) {
    isScheduled = true;
    releaseInteractionHolds = blockActiveInteractions('wait-for-fastdom');
    requestAnimationFrame(flush);
  }
}

function createCancellableTask(fn: TaskFn, queue: Task[]): CancellablePromise {
  let task: Task;

  const promise = new Promise<void>((resolve, reject) => {
    task = { fn, resolve, reject };
    queue.push(task);
    scheduleFlush();
  }) as CancellablePromise;

  promise.cancel = () => {
    measureQueue = measureQueue.filter((t) => t !== task);
    updateQueue = updateQueue.filter((t) => t !== task);
  };

  return promise;
}

/**
 * Schedules a DOM read task (e.g., getBoundingClientRect, offsetWidth).
 * @returns Promise that resolves when task completes. Call .cancel() to abort.
 */
export function measure(fn: TaskFn): CancellablePromise {
  return createCancellableTask(fn, measureQueue);
}

/**
 * Schedules a DOM write task (e.g., style.width, classList.add).
 * @returns Promise that resolves when task completes. Call .cancel() to abort.
 */
export function update(fn: TaskFn): CancellablePromise {
  return createCancellableTask(fn, updateQueue);
}

/**
 * Flush all pending measure/update tasks immediately.
 * Intended for use in tests to avoid depending on requestAnimationFrame timing.
 */
export function flushFastdomForTesting(): void {
  while (measureQueue.length > 0 || updateQueue.length > 0 || isScheduled) {
    flush();
  }
}
