import type { CSSObject, SerializedStyles } from '@emotion/react';
import { css } from '@emotion/react';
import { Input as AntDInput } from 'antd';
import React, { forwardRef, useCallback, useEffect, useMemo, useRef } from 'react';

import type { InputProps } from './common';
import { useFormContext } from '../../development/Form/Form';
import type { Theme } from '../../theme';
import type { ButtonSize } from '../Button';
import {
  DesignSystemEventProviderAnalyticsEventTypes,
  DesignSystemEventProviderComponentTypes,
  useDesignSystemEventComponentCallbacks,
} from '../DesignSystemEventProvider/DesignSystemEventProvider';
import { DesignSystemAntDConfigProvider, getAnimationCss } from '../DesignSystemProvider';
import { useDesignSystemTheme } from '../Hooks/useDesignSystemTheme';
import { LockIcon } from '../Icon';
import type { ValidationState } from '../types';
import { getValidationStateColor, importantify } from '../utils/css-utils';
import { addDebugOutlineIfEnabled } from '../utils/debug';
import { safex, serverSideSafe } from '../utils/safex';
import { useCallbackOnEnter } from '../utils/useCallbackOnEnter';
import { useCallbackOnceUntilReset } from '../utils/useCallbackOnceUntilReset';
import { useChainEventHandlers } from '../utils/useChainEventHandlers';

interface InputStylesOptions {
  useFocusWithin?: boolean;
}

const SMALL_INPUT_HEIGHT = 24;

export const getInputStyles = (
  clsPrefix: string,
  theme: Theme,
  {
    validationState,
    type,
    hasValue,
    locked,
    size,
  }: {
    validationState?: ValidationState;
    type?: string;
    hasValue?: boolean;
    locked?: boolean;
    size?: ButtonSize;
  },
  { useFocusWithin = false }: InputStylesOptions,
): CSSObject => {
  const inputClass = `.${clsPrefix}-input`;
  const affixClass = `.${clsPrefix}-input-affix-wrapper`;
  const affixClassDisabled = `.${clsPrefix}-input-affix-wrapper-disabled`;
  const affixClassFocused = `.${clsPrefix}-input-affix-wrapper-focused`;
  const clearIcon = `.${clsPrefix}-input-clear-icon`;
  const prefixIcon = `.${clsPrefix}-input-prefix`;
  const suffixIcon = `.${clsPrefix}-input-suffix`;

  const validationColor = getValidationStateColor(theme, validationState);

  const focusSpecifier = useFocusWithin ? 'focus-within' : 'focus';

  const styles = {
    '&&': {
      fontSize: theme.typography.fontSizeBase,
      lineHeight: theme.typography.lineHeightBase,
      ...(size === 'small' ? { height: SMALL_INPUT_HEIGHT } : { minHeight: theme.general.heightSm }),
      ...(size === 'small' && {
        paddingLeft: theme.spacing.sm,
        paddingRight: theme.spacing.sm,
      }),
      borderColor: theme.colors.actionDefaultBorderDefault,
      ...(validationState && { borderColor: validationColor }),

      '&:hover': {
        borderColor: validationState ? validationColor : theme.colors.actionPrimaryBackgroundHover,
      },

      [`&:${focusSpecifier}`]: {
        outlineColor: validationState ? validationColor : theme.colors.actionDefaultBorderFocus,
        outlineWidth: 2,
        outlineOffset: -2,
        outlineStyle: 'solid',
        borderColor: 'transparent',
      },

      '&:focus-visible': {
        outlineColor: validationState ? validationColor : theme.colors.actionDefaultBorderFocus,
        outlineWidth: 2,
        outlineOffset: -2,
        outlineStyle: 'solid',
        borderColor: 'transparent',
      },

      [`& + .${clsPrefix}-form-message`]: {
        marginTop: theme.spacing.sm,
      },
    },

    [`&${inputClass}, ${inputClass}`]: {
      backgroundColor: 'transparent',
      borderRadius: theme.borders.borderRadiusSm,
      '&:disabled': {
        backgroundColor: theme.colors.actionDisabledBackground,
        color: theme.colors.actionDisabledText,
        borderColor: theme.colors.actionDisabledBorder,
      },
      '&::placeholder': {
        color: theme.colors.textPlaceholder,
      },
    },

    [`&${affixClass}`]: {
      backgroundColor: 'transparent',
      fontSize: theme.typography.fontSizeBase,
      lineHeight: theme.typography.lineHeightBase,
      paddingTop: 5,
      paddingBottom: 5,
      ...(size === 'small' ? { height: SMALL_INPUT_HEIGHT } : { minHeight: theme.general.heightSm }),

      '::before': {
        lineHeight: theme.typography.lineHeightBase,
      },

      '&:hover': {
        borderColor: validationState ? validationColor : theme.colors.actionPrimaryBackgroundHover,
      },

      [`input.${clsPrefix}-input`]: {
        fontSize: 'inherit',
        borderRadius: 0,
      },
    },

    [`&${affixClassDisabled}`]: {
      backgroundColor: theme.colors.actionDisabledBackground,
    },

    [`&${affixClassFocused}`]: {
      boxShadow: 'none',
      [`&&, &:${focusSpecifier}`]: {
        outlineColor: validationState ? validationColor : theme.colors.actionDefaultBorderFocus,
        outlineWidth: 2,
        outlineOffset: -2,
        outlineStyle: 'solid',
        boxShadow: 'none',
        borderColor: 'transparent',
      },
    },

    [clearIcon]: {
      fontSize: theme.typography.fontSizeSm,
    },

    [prefixIcon]: {
      marginRight: theme.spacing.sm,
      color: theme.colors.textSecondary,
    },

    [suffixIcon]: {
      marginLeft: theme.spacing.sm,
      color: theme.colors.textSecondary,

      ...(!hasValue &&
        type === 'number' && {
          display: 'none',
        }),
    },

    ...(locked
      ? {
          [`&${affixClass}`]: {
            backgroundColor: theme.colors.backgroundSecondary,
          },
          [`input.${clsPrefix}-input`]: {
            backgroundColor: `${theme.colors.backgroundSecondary} !important`,
            color: `${theme.colors.textPrimary} !important`,
          },
        }
      : {}),

    ...getAnimationCss(theme.options.enableAnimation),
  };

  return styles;
};

export const getInputEmotionStyles = (
  clsPrefix: string,
  theme: Theme,
  {
    validationState,
    type,
    hasValue,
    locked,
    size,
  }: {
    validationState?: ValidationState;
    type?: string;
    hasValue?: boolean;
    locked?: boolean;
    size?: ButtonSize;
  },
): SerializedStyles => {
  const styles = getInputStyles(clsPrefix, theme, { validationState, type, hasValue, locked, size }, {});
  return css(importantify(styles));
};

export const Input = forwardRef<AntDInput, InputProps>(function Input(
  {
    validationState,
    autoComplete = 'off',
    dangerouslySetAntdProps,
    dangerouslyAppendEmotionCSS,
    onChange,
    onClear,
    onFocus,
    onPressEnter,
    onWheel,
    onCompositionStart,
    onCompositionEnd,
    componentId,
    shouldPreventFormSubmission,
    analyticsEvents,
    readOnly,
    locked,
    size = 'middle',
    ...props
  },
  ref,
) {
  const emitOnView = safex('databricks.fe.observability.defaultComponentView.input', false);
  const disableNumberInputWheelValueChange = serverSideSafe(
    'databricks.fe.designsystem.disableNumberInputWheelValueChange',
    false,
  );
  const formContext = useFormContext();
  const { classNamePrefix, theme } = useDesignSystemTheme();
  const [hasValue, setHasValue] = React.useState(
    props.value !== undefined && props.value !== null && props.value !== '',
  );

  const memoizedAnalyticsEvents = useMemo(
    () =>
      analyticsEvents ??
      (emitOnView
        ? [
            DesignSystemEventProviderAnalyticsEventTypes.OnValueChange,
            DesignSystemEventProviderAnalyticsEventTypes.OnView,
          ]
        : [DesignSystemEventProviderAnalyticsEventTypes.OnValueChange]),
    [analyticsEvents, emitOnView],
  );
  const eventContext = useDesignSystemEventComponentCallbacks({
    componentType: DesignSystemEventProviderComponentTypes.Input,
    componentId,
    analyticsEvents: memoizedAnalyticsEvents,
    valueHasNoPii: false,
  });

  const firstView = useRef(true);
  useEffect(() => {
    if (firstView.current) {
      eventContext.onView();
      firstView.current = false;
    }
  }, [eventContext]);

  // Prevents multiple onValueChange triggers until after a focus event resets it.
  const { callbackOnceUntilReset: sendAnalyticsEventOncePerFocus, reset: resetSendAnalyticsEventOnFocus } =
    useCallbackOnceUntilReset(eventContext.onValueChange);

  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      sendAnalyticsEventOncePerFocus();
      // If the input is cleared, call the onClear handler, but only
      // if the event is not an input event -- which is the case when you click the
      // ant-provided (X) button.
      if (!e.target.value && e.nativeEvent instanceof InputEvent === false && onClear) {
        onClear?.();
        setHasValue(false);
      } else {
        onChange?.(e);
        setHasValue(Boolean(e.target.value));
      }
    },
    [onChange, onClear, sendAnalyticsEventOncePerFocus],
  );

  const handleFocus = useCallback(
    (e: React.FocusEvent<HTMLInputElement>) => {
      resetSendAnalyticsEventOnFocus();
      onFocus?.(e);
    },
    [onFocus, resetSendAnalyticsEventOnFocus],
  );

  const handleWheel = useCallback(
    (e: React.WheelEvent<HTMLInputElement>) => {
      /*
        For additional context, read CJ-72625, PR 1693195 and https://github.com/facebook/react/issues/32156

        The code below fixes an issue when the following conditions are met:
          - An input with type = "number" is focused
          - The mouse is inside the input
          - The user scrolls the mouse wheel

        This can result in unexpected behavior where the input value changes, even though the user might intend
        to scroll on the page.

        React adds a wheel event listener to the input element. On Chrome, when an input with type = "number"
        has a wheel event listener attached, when receiving a WheelEvent, it will also update the input value.
        On Firefox, the input value is not updated.

        The fix here is to blur the input when all the above conditions are met, preventing the input value
        from being changed. See https://stackoverflow.com/questions/63224459/disable-scrolling-on-input-type-number-in-react.
      */
      if (props.type === 'number' && !onWheel && disableNumberInputWheelValueChange) {
        e.currentTarget.blur();
        return;
      }
      onWheel?.(e);
    },
    [disableNumberInputWheelValueChange, onWheel, props.type],
  );

  const onFormSubmit = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (!formContext.formRef?.current) return;
      e.preventDefault();
      formContext.formRef.current.requestSubmit();
    },
    [formContext.formRef],
  );

  const submitHandlers = useCallbackOnEnter<HTMLInputElement>({
    callback: onFormSubmit,
    allowBasicEnter: !shouldPreventFormSubmission,
    allowPlatformEnter: !shouldPreventFormSubmission,
  });

  const onPressEnterChain = useChainEventHandlers(
    useMemo(
      () => ({ handlers: [submitHandlers.onKeyDown, onPressEnter], stopOnDefaultPrevented: false }),
      [submitHandlers.onKeyDown, onPressEnter],
    ),
  );

  const onCompositionStartChain = useChainEventHandlers(
    useMemo(
      () => ({ handlers: [submitHandlers.onCompositionStart, onCompositionStart] }),
      [submitHandlers.onCompositionStart, onCompositionStart],
    ),
  );

  const onCompositionEndChain = useChainEventHandlers(
    useMemo(
      () => ({ handlers: [submitHandlers.onCompositionEnd, onCompositionEnd] }),
      [submitHandlers.onCompositionEnd, onCompositionEnd],
    ),
  );

  return (
    <DesignSystemAntDConfigProvider>
      <AntDInput
        {...addDebugOutlineIfEnabled()}
        autoComplete={autoComplete}
        data-validation={validationState}
        ref={ref}
        css={[
          getInputEmotionStyles(classNamePrefix, theme, {
            validationState,
            type: props.type,
            hasValue,
            locked,
            size,
          }),
          dangerouslyAppendEmotionCSS,
        ]}
        onChange={handleChange}
        onFocus={handleFocus}
        onPressEnter={onPressEnterChain}
        onWheel={handleWheel}
        onCompositionStart={onCompositionStartChain}
        onCompositionEnd={onCompositionEndChain}
        {...props}
        readOnly={locked || readOnly}
        suffix={locked ? <LockIcon /> : props.suffix}
        {...dangerouslySetAntdProps}
        {...eventContext.dataComponentProps}
      />
    </DesignSystemAntDConfigProvider>
  );
});
