import { type CSSObject, Global, css, type SerializedStyles } from '@emotion/react';

import type { Theme } from '../../theme';
import { useDesignSystemTheme } from '../Hooks';
import { serverSideSafe } from '../utils/safex';

export const getGlobalStyles = (theme: Theme): SerializedStyles => {
  const bodyStyles: CSSObject = {
    backgroundColor: theme.colors.backgroundPrimary,
    color: theme.colors.textPrimary,
    '--dubois-global-background-color': theme.colors.backgroundPrimary,
    '--dubois-global-color': theme.colors.textPrimary,
    ...globalResetStyles(),
  };

  return css({
    'body, .mfe-root': bodyStyles,
  });
};

const globalResetStyles = (): CSSObject => {
  return serverSideSafe('databricks.fe.eda.enableBorderBoxCssReset', false)
    ? {
        boxSizing: 'border-box',
        '*, *::before, *::after': { boxSizing: 'border-box' },
      }
    : {
        '[class^=du-bois]': {
          boxSizing: 'border-box',
          '*, *::before, *::after': { boxSizing: 'border-box' },
        },
      };
};

// Only used in storybook
export const getGlobalResetStyles = () => {
  return css(globalResetStyles());
};

export const ApplyGlobalStyles: React.FC<React.PropsWithChildren<unknown>> = () => {
  const { theme } = useDesignSystemTheme();
  return <Global styles={getGlobalStyles(theme)} />;
};
