import type { KeyboardEvent, ReactNode } from 'react';
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import { Button } from '../Button/Button';
import { useDesignSystemTheme } from '../Hooks/useDesignSystemTheme';
import { ChevronLeftIcon, ChevronRightIcon } from '../Icon/__generated/icons';
import { Typography } from '../Typography/Typography';

const YEARS_PER_PAGE = 12;

export interface YearPickerGridProps {
  /** The currently selected year as a Date. Only the year component is used. */
  value?: Date;
  /** Callback fired when a year is selected. The Date is set to Jan 1 of the selected year. */
  onSelect: (date: Date) => void;
  /** Optional: The minimum selectable date. Only the year component is used. */
  min?: Date;
  /** Optional: The maximum selectable date. Only the year component is used. */
  max?: Date;
  /** Optional: Start of a date range. Used to highlight cells between rangeFrom and rangeTo. */
  rangeFrom?: Date;
  /** Optional: End of a date range. Used to highlight cells between rangeFrom and rangeTo. */
  rangeTo?: Date;
  /** Optional: Receives the cell date and the full default button element. The caller can wrap it
   * (e.g., add a dot indicator) or replace it entirely (e.g., to apply custom `disabled` logic). */
  renderCellContent?: (date: Date, defaultContent: ReactNode) => ReactNode;
  /** Optional: Additional predicate to disable individual year cells beyond `min`/`max`. */
  isDateDisabled?: (date: Date) => boolean;
}

interface YearCellProps {
  year: number;
  index: number;
  selected: boolean;
  disabled: boolean;
  isCurrentYear: boolean;
  rangeFrom: Date | undefined;
  rangeTo: Date | undefined;
  focusedIndex: number;
  onSelect: (year: number) => void;
  onKeyDown: (event: KeyboardEvent<HTMLButtonElement>, index: number) => void;
  onFocus: (index: number) => void;
  renderCellContent?: (date: Date, defaultContent: ReactNode) => ReactNode;
}

function getGridCellCss(
  theme: ReturnType<typeof useDesignSystemTheme>['theme'],
  isRangeStart: boolean,
  isRangeEnd: boolean,
  isRangeMiddle: boolean,
  index: number,
) {
  return {
    padding: 0,
    // Use actionTertiaryBackgroundPress for range background to match DayPicker's --rdp-background-color
    backgroundColor: isRangeMiddle ? theme.colors.actionTertiaryBackgroundPress : 'transparent',
    // Range start: round left edge, square right edge (flush with middle range)
    ...(isRangeStart && {
      borderTopLeftRadius: theme.general.borderRadiusBase,
      borderBottomLeftRadius: theme.general.borderRadiusBase,
      borderTopRightRadius: 0,
      borderBottomRightRadius: 0,
      backgroundColor: theme.colors.actionTertiaryBackgroundPress,
    }),
    // Range end: round right edge, square left edge (flush with middle range)
    ...(isRangeEnd && {
      borderTopRightRadius: theme.general.borderRadiusBase,
      borderBottomRightRadius: theme.general.borderRadiusBase,
      borderTopLeftRadius: 0,
      borderBottomLeftRadius: 0,
      backgroundColor: theme.colors.actionTertiaryBackgroundPress,
    }),
    // When start === end, round both sides
    ...(isRangeStart &&
      isRangeEnd && {
        borderRadius: theme.general.borderRadiusBase,
      }),
    // Round left edge for first column cells in range
    ...(isRangeMiddle &&
      index % 4 === 0 && {
        borderTopLeftRadius: theme.general.borderRadiusBase,
        borderBottomLeftRadius: theme.general.borderRadiusBase,
      }),
    // Round right edge for last column cells in range
    ...(isRangeMiddle &&
      index % 4 === 3 && {
        borderTopRightRadius: theme.general.borderRadiusBase,
        borderBottomRightRadius: theme.general.borderRadiusBase,
      }),
  };
}

function getButtonCss(
  theme: ReturnType<typeof useDesignSystemTheme>['theme'],
  selected: boolean,
  isRangeStart: boolean,
  isRangeEnd: boolean,
  isCurrentYear: boolean,
) {
  return {
    width: '100%',
    // DS Button's importantify wraps borderColor with !important, so we must override here.
    // borderWidth is always 2px (matching DayPicker's --rdp-outline) so focus doesn't cause layout shift.
    borderColor: 'transparent !important',
    borderWidth: '2px !important',
    boxShadow: 'none !important',
    '&[disabled]': {
      borderColor: 'transparent !important',
    },
    fontWeight: isCurrentYear ? 'bold' : 'normal',
    // Non-selected focused: DayPicker shows light blue bg + single inner border ring (no outer outline).
    // Selected+focused gets the 2-ring style (inner + outer with gap) via the selected override below.
    // borderWidth ensures the 2px ring matches DayPicker's --rdp-outline (2px solid accent).
    '&:focus-visible': {
      backgroundColor: `${theme.colors.actionTertiaryBackgroundPress} !important`,
      borderColor: `${theme.colors.actionPrimaryBackgroundDefault} !important`,
      outlineColor: 'transparent !important',
    },
    // Use the exact same colors as DayPicker for selected/range start/end cells.
    // Manually applying actionPrimaryBackground* + #fff text ensures consistent
    // appearance across light and dark themes without relying on Button type='primary'.
    ...((selected || isRangeStart || isRangeEnd) && {
      backgroundColor: `${theme.colors.actionPrimaryBackgroundDefault} !important`,
      color: '#fff !important',
      '&:hover': {
        backgroundColor: `${theme.colors.actionPrimaryBackgroundHover} !important`,
        color: '#fff !important',
        // Keep border transparent on hover — DS Button shows a border on hover by default
        borderColor: 'transparent !important',
      },
      '&:active': {
        backgroundColor: `${theme.colors.actionPrimaryBackgroundPress} !important`,
        color: '#fff !important',
      },
      // Keyboard focus on selected cell: DayPicker's .button:focus-visible:not([disabled]) has
      // higher specificity than .day_selected, so selected+focused shows the hover (light blue)
      // background with dark text. Match that behavior here.
      '&:focus-visible': {
        backgroundColor: `${theme.colors.actionTertiaryBackgroundPress} !important`,
        color: 'inherit !important',
        borderColor: `${theme.colors.actionPrimaryBackgroundDefault} !important`,
        outlineColor: `${theme.colors.actionPrimaryBackgroundDefault} !important`,
        outlineOffset: '2px !important',
      },
    }),
    ...(!(selected || isRangeStart || isRangeEnd) && {
      backgroundColor: 'transparent !important',
      '&:hover:not([disabled])': {
        backgroundColor: `${theme.colors.actionTertiaryBackgroundPress} !important`,
        color: 'inherit !important',
        // Keep border transparent on hover — DS Button shows a border on hover by default
        borderColor: 'transparent !important',
      },
    }),
    // Match button border-radius to gridcell container for range start/end
    ...(isRangeStart &&
      !isRangeEnd && {
        borderTopRightRadius: 0,
        borderBottomRightRadius: 0,
      }),
    ...(isRangeEnd &&
      !isRangeStart && {
        borderTopLeftRadius: 0,
        borderBottomLeftRadius: 0,
      }),
  };
}

function YearCell({
  year,
  index,
  selected,
  disabled,
  isCurrentYear,
  rangeFrom,
  rangeTo,
  focusedIndex,
  onSelect,
  onKeyDown,
  onFocus,
  renderCellContent,
}: YearCellProps): JSX.Element {
  const { theme } = useDesignSystemTheme();
  const rangeFromYear = rangeFrom?.getFullYear();
  const rangeToYear = rangeTo?.getFullYear();
  const inRange =
    rangeFromYear !== undefined && rangeToYear !== undefined && year >= rangeFromYear && year <= rangeToYear;
  const isRangeStart = rangeFromYear !== undefined && year === rangeFromYear;
  const isRangeEnd = rangeToYear !== undefined && year === rangeToYear;
  const isRangeMiddle = inRange && !isRangeStart && !isRangeEnd;
  const defaultButton = (
    <Button
      componentId="datepicker-year-grid-cell"
      aria-label={String(year)}
      data-selected={selected || undefined}
      aria-current={isCurrentYear ? 'date' : undefined}
      disabled={disabled}
      tabIndex={index === focusedIndex ? 0 : -1}
      onClick={() => !disabled && onSelect(year)}
      onKeyDown={(e) => onKeyDown(e, index)}
      onFocus={() => onFocus(index)}
      css={getButtonCss(theme, selected, isRangeStart, isRangeEnd, isCurrentYear)}
    >
      {year}
    </Button>
  );
  return (
    <div key={year} role="gridcell" css={getGridCellCss(theme, isRangeStart, isRangeEnd, isRangeMiddle, index)}>
      {renderCellContent ? renderCellContent(new Date(year, 0, 1), defaultButton) : defaultButton}
    </div>
  );
}

/**
 * YearPickerGrid renders a 4x3 grid of years with decade navigation.
 * It is used inside the DatePicker when `granularity='year'` is set.
 */
export function YearPickerGrid({
  value,
  onSelect,
  min,
  max,
  rangeFrom,
  rangeTo,
  renderCellContent,
  isDateDisabled,
}: YearPickerGridProps): JSX.Element {
  const { theme } = useDesignSystemTheme();
  const selectedYear = value?.getFullYear();

  // Compute the initial decade start from the selected year or the current year
  const initialDecadeStart = useMemo(() => {
    const year = selectedYear ?? new Date().getFullYear();
    return year - (year % YEARS_PER_PAGE);
  }, [selectedYear]);

  const [decadeStart, setDecadeStart] = useState(initialDecadeStart);

  const minYear = min?.getFullYear();
  const maxYear = max?.getFullYear();

  const years = useMemo(() => {
    const result: number[] = [];
    for (let i = 0; i < YEARS_PER_PAGE; i++) {
      result.push(decadeStart + i);
    }
    return result;
  }, [decadeStart]);

  const isDisabled = useCallback(
    (year: number) => {
      if (minYear !== undefined && year < minYear) return true;
      if (maxYear !== undefined && year > maxYear) return true;
      if (isDateDisabled?.(new Date(year, 0, 1))) return true;
      return false;
    },
    [minYear, maxYear, isDateDisabled],
  );

  // Roving tabindex: track which grid cell is the "active" tabbable one.
  // This ensures exactly one grid cell always has tabIndex=0 so Tab can reach the grid.
  const getInitialFocusIndex = useCallback(
    (currentYears: number[]) => {
      if (selectedYear !== undefined) {
        const idx = selectedYear - decadeStart;
        if (idx >= 0 && idx < YEARS_PER_PAGE && !isDisabled(currentYears[idx] ?? 0)) return idx;
      }
      // Fall back to first non-disabled cell so keyboard navigation always has a starting point
      const firstEnabled = currentYears.findIndex((y) => !isDisabled(y));
      return firstEnabled >= 0 ? firstEnabled : 0;
    },
    [selectedYear, decadeStart, isDisabled],
  );

  const [focusedIndex, setFocusedIndex] = useState(() =>
    getInitialFocusIndex(Array.from({ length: YEARS_PER_PAGE }, (_, i) => initialDecadeStart + i)),
  );

  // Update focused index when decade changes (e.g. after prev/next navigation)
  useEffect(() => {
    setFocusedIndex(getInitialFocusIndex(years));
  }, [decadeStart, selectedYear, getInitialFocusIndex, years]);

  const handlePrevDecade = useCallback(() => {
    setDecadeStart((prev) => prev - YEARS_PER_PAGE);
  }, []);

  const handleNextDecade = useCallback(() => {
    setDecadeStart((prev) => prev + YEARS_PER_PAGE);
  }, []);

  const handleSelectYear = useCallback(
    (year: number) => {
      onSelect(new Date(year, 0, 1));
    },
    [onSelect],
  );

  const gridRef = useRef<HTMLDivElement>(null);

  const focusCellAtIndex = useCallback((nextIndex: number) => {
    const grid = gridRef.current;
    if (grid) {
      const buttons = grid.querySelectorAll<HTMLButtonElement>('[role="gridcell"] button');
      buttons[nextIndex]?.focus();
    }
  }, []);

  const handleKeyDown = useCallback((event: KeyboardEvent<HTMLButtonElement>, index: number) => {
    let nextIndex = index;
    switch (event.key) {
      case 'ArrowRight':
        event.preventDefault();
        if (index >= YEARS_PER_PAGE - 1) {
          // At the end of the grid — navigate to next page, focus first cell
          setDecadeStart((prev) => prev + YEARS_PER_PAGE);
          nextIndex = 0;
        } else {
          nextIndex = index + 1;
        }
        break;
      case 'ArrowLeft':
        event.preventDefault();
        if (index <= 0) {
          // At the start of the grid — navigate to previous page, focus last cell
          setDecadeStart((prev) => prev - YEARS_PER_PAGE);
          nextIndex = YEARS_PER_PAGE - 1;
        } else {
          nextIndex = index - 1;
        }
        break;
      case 'ArrowDown':
        event.preventDefault();
        if (index + 4 >= YEARS_PER_PAGE) {
          // At the bottom of the grid — navigate to next page, keep column position
          setDecadeStart((prev) => prev + YEARS_PER_PAGE);
          nextIndex = index % 4; // keep same column, first row
        } else {
          nextIndex = index + 4;
        }
        break;
      case 'ArrowUp':
        event.preventDefault();
        if (index - 4 < 0) {
          // At the top of the grid — navigate to previous page, keep column position
          setDecadeStart((prev) => prev - YEARS_PER_PAGE);
          nextIndex = YEARS_PER_PAGE - 4 + (index % 4); // keep same column, last row
        } else {
          nextIndex = index - 4;
        }
        break;
      // Enter and Space are handled by the DS Button's onClick — no need to handle here
      default:
        return;
    }
    setFocusedIndex(nextIndex);
  }, []);

  // Navigation buttons are never disabled — users should always be able to browse pages.
  // Only individual grid cells are disabled by min/max constraints.
  const isPrevDisabled = false;
  const isNextDisabled = false;

  // Focus the active grid cell whenever focusedIndex changes (covers both initial mount
  // and post-navigation focus after arrow key presses or decade page changes).
  useEffect(() => {
    focusCellAtIndex(focusedIndex);
  }, [focusedIndex, focusCellAtIndex]);

  return (
    <div style={{ padding: theme.spacing.xs, minWidth: 225 }}>
      {/* Navigation header */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          padding: `0 ${theme.spacing.xs}px`,
          marginBottom: theme.spacing.xs,
        }}
      >
        <Button
          componentId="datepicker-year-grid-prev"
          aria-label="Previous decade"
          icon={<ChevronLeftIcon />}
          onClick={handlePrevDecade}
          disabled={isPrevDisabled}
          size="small"
        />
        <Typography.Text bold aria-live="polite">
          {decadeStart} – {decadeStart + YEARS_PER_PAGE - 1}
        </Typography.Text>
        <Button
          componentId="datepicker-year-grid-next"
          aria-label="Next decade"
          icon={<ChevronRightIcon />}
          onClick={handleNextDecade}
          disabled={isNextDisabled}
          size="small"
        />
      </div>

      {/* Year grid */}
      <div
        ref={gridRef}
        role="grid"
        aria-label="Year picker"
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(4, 1fr)',
        }}
      >
        {years.map((year, index) => (
          <YearCell
            key={year}
            year={year}
            index={index}
            selected={year === selectedYear}
            disabled={isDisabled(year)}
            isCurrentYear={year === new Date().getFullYear()}
            rangeFrom={rangeFrom}
            rangeTo={rangeTo}
            focusedIndex={focusedIndex}
            onSelect={handleSelectYear}
            onKeyDown={handleKeyDown}
            onFocus={setFocusedIndex}
            renderCellContent={renderCellContent}
          />
        ))}
      </div>
    </div>
  );
}
